1	/**
2	 * A single function used to scroll a DOM node into view, optionally taking into
3	 * account that it may be obscured by the custom keypad. The logic makes the
4	 * strong assumption that the keypad will be anchored to the bottom of the page
5	 * in calculating its height, as this method may be called before the keypad has
6	 * animated into view.
7	 */
8	
9	// HACK(charlie): This should be injected by webapp somehow.
10	// TODO(charlie): Add a link to the khan/frontend location as soon as the
11	// footer has settled down.
12	const toolbarHeightPx = 60;
13	
14	export const scrollIntoView = (containerNode, keypadNode) => {
15	    const containerBounds = containerNode.getBoundingClientRect();
16	    const containerBottomPx = containerBounds.bottom;
17	    const containerTopPx = containerBounds.top;
18	
19	    // Get the element that scrolls the document.
20	    const scrollNode = document.scrollingElement;
21	
22	    const desiredMarginPx = 16;
23	
24	    if (keypadNode) {
25	        // NOTE(charlie): We can't use the bounding rect of the keypad,
26	        // as it is likely in the process of animating in. Instead, to
27	        // calculate its top, we make the strong assumption that the
28	        // keypad will end up anchored at the bottom of the page, but above the
29	        // toolbar, and use its height, which is known at this point. Note that,
30	        // in the native apps (where the toolbar is rendered natively), this
31	        // will result in us leaving excess space between the input and the
32	        // keypad, but that seems okay.
33	        const pageHeightPx = window.innerHeight;
34	        const keypadHeightPx = keypadNode.clientHeight;
35	        const keypadTopPx = pageHeightPx - (keypadHeightPx + toolbarHeightPx);
36	
37	        if (containerBottomPx > keypadTopPx) {
38	            // If the input would be obscured by the keypad, scroll such that
39	            // the bottom of the input is just above the top of the keypad,
40	            // taking care not to scroll the input out of view.
41	            const scrollOffset = Math.min(
42	                containerBottomPx - keypadTopPx + desiredMarginPx,
43	                containerTopPx,
44	            );
45	
46	            if (scrollNode) {
47	                scrollNode.scrollTop += scrollOffset;
48	            }
49	            return;
50	        }
51	    }
52	
53	    // Alternatively, if the input is out of the viewport or nearly out
